const path = "~/contacts.yaml";
const text = await space.api.fileRead(path, "utf8");
const data = space.utils.yaml.parse(text);

function updateMrKowalski(node) {
  if (!node || typeof node !== "object") return false;
  let changed = false;

  if (Array.isArray(node)) {
    for (const item of node) changed = updateMrKowalski(item) || changed;
    return changed;
  }

  if (Object.prototype.hasOwnProperty.call(node, "mr_kowalski")) {
    const v = node.mr_kowalski;
    if (typeof v === "string") {
      node.mr_kowalski = "John Ronald Kowalski";
      return true;
    }
    if (v && typeof v === "object") {
      if (v.full_name !== "John Ronald Kowalski") {
        v.full_name = "John Ronald Kowalski";
        return true;
      }
    }
  }

  for (const k of Object.keys(node)) changed = updateMrKowalski(node[k]) || changed;
  return changed;
}

updateMrKowalski(data);
await space.api.fileWrite(path, space.utils.yaml.stringify(data), "utf8");
return "updated";

